                    os.nice(10, proc.info['pid'])
                    print(f'Lowered priority of {proc.info["name"]} (PID: {proc.info["pid"]})')
                except (PermissionError, psutil.NoSuchProcess):
                    pass

        # Optimize memory
        for proc in psutil.process_iter(['pid']):
            try:
                # Terminate unnecessary processes
                if proc.info['pid'] in [proc.pid for proc in psutil.memory_stats()['processes'].values() if proc.info['num_threads'] < 2]:
                    psutil.terminate(proc.info['pid'])
                    print(f'Terminated low-thread process with PID: {proc.info["pid"]}')
            except (PermissionError, psutil.NoSuchProcess):
                pass

        # Clean up temporary files
        for folder in ['C:\\temp', 'C:\\users\\public\\documents\\temporary']:
            for file in os.listdir(folder):
                try:
                    os.remove(os.path.join(folder, file))
                    print(f'Removed temporary file: {file}')
                except (PermissionError, OSError):
                    pass

def main():
    # Run optimization only during off-peak hours
    if 1 <= time.localtime().tm_hour < 6:
        optimize_system()
    else:
        print("Not performing optimization during peak hours.")

if __name__ == "__main__":
    main()
